import React, { useState } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import {
  LayoutDashboard, FolderKanban, Bell, BarChart2,
  User, LogOut, Settings, Zap, ChevronDown
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { getInitials } from '../../utils/helpers';
import useNotifications from '../../hooks/useNotifications';

export default function AppLayout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const { unreadCount } = useNotifications();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const navItems = [
    { to: '/dashboard',    icon: <LayoutDashboard size={16} />, label: 'Dashboard' },
    { to: '/projects',     icon: <FolderKanban size={16} />,    label: 'Projects' },
    { to: '/notifications',icon: <Bell size={16} />,            label: 'Notifications', badge: unreadCount },
  ];

  return (
    <div className="app-shell">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-logo">
          <div className="sidebar-logo-icon">
            <Zap size={16} color="#fff" />
          </div>
          <span className="sidebar-logo-text">WorkSync</span>
        </div>

        <div className="sidebar-section" style={{ flex: 1 }}>
          <div className="sidebar-section-label">Navigation</div>
          {navItems.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              className={({ isActive }) => `sidebar-nav-item${isActive ? ' active' : ''}`}
            >
              {item.icon}
              {item.label}
              {item.badge > 0 && <span className="count">{item.badge}</span>}
            </NavLink>
          ))}
        </div>

        {/* User section */}
        <div className="sidebar-bottom">
          <div className="dropdown" style={{ width: '100%' }}>
            <button
              className="sidebar-nav-item"
              style={{ width: '100%' }}
              onClick={() => setUserMenuOpen(o => !o)}
            >
              <div className="avatar avatar-sm">{getInitials(user?.name)}</div>
              <span className="truncate" style={{ flex: 1, fontSize: '0.82rem' }}>{user?.name}</span>
              <ChevronDown size={13} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
            </button>
            {userMenuOpen && (
              <div className="dropdown-menu" style={{ bottom: '100%', top: 'auto', marginBottom: 6 }}>
                <button className="dropdown-item" onClick={() => { navigate('/profile'); setUserMenuOpen(false); }}>
                  <User size={14} /> Profile
                </button>
                <button className="dropdown-item danger" onClick={handleLogout}>
                  <LogOut size={14} /> Logout
                </button>
              </div>
            )}
          </div>
        </div>
      </aside>

      {/* Header */}
      <header className="header">
        <div className="header-left">
          <span className="header-title">WorkSync</span>
        </div>
        <div className="header-right">
          <NavLink to="/notifications" className={({ isActive }) => `btn btn-ghost btn-icon${isActive ? ' active' : ''}`} style={{ position: 'relative' }}>
            <Bell size={17} />
            {unreadCount > 0 && (
              <span style={{
                position: 'absolute', top: 4, right: 4,
                width: 7, height: 7,
                background: 'var(--accent)', borderRadius: '50%',
              }} />
            )}
          </NavLink>
          <button className="btn btn-ghost btn-icon" onClick={() => navigate('/profile')}>
            <div className="avatar avatar-sm">{getInitials(user?.name)}</div>
          </button>
        </div>
      </header>

      {/* Main content */}
      <main className="main-content">
        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
